private static void ApplySwaggerTagAttribute(
    OpenApiDocument document,
    string controllerName,
    IEnumerable<object> customAttributes)
{
    var swaggerTagAttribute = customAttributes
        .OfType<SwaggerTagAttribute>()
        .FirstOrDefault();

    if (swaggerTagAttribute is null)
    {
        return;
    }

    var tag = document.Tags.FirstOrDefault((p) => p?.Name == controllerName);

    if (tag is null)
    {
        tag = new() { Name = controllerName };
        document.Tags.Add(tag);
    }

    tag.Description ??= swaggerTagAttribute.Description;

    if (swaggerTagAttribute.ExternalDocsUrl is { } url)
    {
        tag.ExternalDocs ??= new OpenApiExternalDocs { Url = new(url) };
    }
}

private void SetClassMap()
        {
            string prefixName = "ant-alert";
            ClassMapper
                .Add("ant-alert")
                .GetIf(() => $"{prefixName}-{_cssMap}", () => CalcType.HasValue)
                .If($"{prefixName}-no-icon", () => !IsShowIcon)
                .If($"{prefixName}-closable", () => Closable)
                .If($"{prefixName}-banner", () => Banner)
                .If($"{prefixName}-with-description", () => !string.IsNullOrEmpty(Description) || ChildContent != null)
                .If($"{prefixName}-motion", () => _isClosing)
                .If($"{prefixName}-motion-leave", () => _isClosing)
                .If($"{prefixName}-motion-leave-active", () => _isClosing && _motionStage == 1)
                .If($"{prefixName}-rtl", () => RTL)
                ;
        }

async Task IAutoCompleteRef.InputKeyDown(KeyboardEventArgs args)
        {
            var key = args.Key;

            if (this._isOpened)
            {
                if (key == "Escape" || key == "Tab")
                {
                    await this.ClosePanel();
                }
                else if (key == "Enter" && this._activeValue != null)
                {
                    await SetSelectedItem(GetActiveItem());
                }
            }
            else if (!_isOptionsZero)
            {
                await this.OpenPanel();
            }

            if (key == "ArrowUp")
            {
                this.SetPreviousItemActive();
            }
            else if (key == "ArrowDown")
            {
                this.SetNextItemActive();
            }
        }

protected override void OnInitialized()
        {
            base.OnInitialized();

            _picker = Mode switch
            {
                CalendarMode.Month => DatePickerType.Date,
                CalendarMode.Year => DatePickerType.Month,
                _ => DatePickerType.Date
            };

            if (ValidRange != null)
            {
                if (Value < ValidRange[0])
                {
                    Value = ValidRange[0];
                }
                else if (Value > ValidRange[1])
                {
                    Value = ValidRange[1];
                }
            }
        }

protected override void OnInitialized()
        {
            if (ChildContent is null && MixedMode == CheckboxGroupMixedMode.ChildContentFirst)
                MixedMode = CheckboxGroupMixedMode.OptionsFirst;

            base.OnInitialized();

            if (Value != null)
            {
                _selectedValues = Value;
                if (Options.IsT0)
                {
                    Options.AsT0.ForEach(opt => opt.Checked = opt.Value.IsIn(_selectedValues));
                }
            }

            _selectedValues ??= Array.Empty<TValue>();
        }

protected override void OnValueChange(TValue[] value)
        {
            base.OnValueChange(value);

            if (Disabled)
            {
                return;
            }

            _selectedValues = value;

            if (Options.Value != null && Options.IsT0)
            {
                Options.AsT0.ForEach(x =>
                {
                    if (!x.Disabled)
                    {
                        x.Checked = x.Value.IsIn(_selectedValues);
                    }
                });
            }
            else
            {
                _checkboxItems.ForEach(x =>
                {
                    var checkBoxValue = ((TValue)x.ItemValue).IsIn(value);
                    x.SetValue(checkBoxValue);
                });
            }
        }

public void SaveCookieToken(HttpContext httpContext, string token)
    {
        Debug.Assert(httpContext != null);
        Debug.Assert(token != null);

        var options = _options.Cookie.Build(httpContext);

        if (_options.Cookie.Path != null)
        {
            options.Path = _options.Cookie.Path;
        }
        else
        {
            var pathBase = httpContext.Request.PathBase.ToString();
            if (!string.IsNullOrEmpty(pathBase))
            {
                options.Path = pathBase;
            }
        }

        httpContext.Response.Cookies.Append(_options.Cookie.Name!, token, options);
    }

