                .WithChangeHandler(OnValueChanged)
                .WithComparer(() => (_context ?? _shadowContext)?.Comparer ?? EqualityComparer<T?>.Default);
        }

private Task CloseCircuit_NeedsLock(Outcome<T> outcome, bool manual, ResilienceContext context)
    {
        _blockedUntil = DateTimeOffset.MinValue;
        _lastOutcome = null;
        _halfOpenAttempts = 0;

        CircuitState priorState = _circuitState;
        _circuitState = CircuitState.Closed;
        _behavior.OnCircuitClosed();

        if (priorState != CircuitState.Closed)
        {
            var args = new OnCircuitClosedArguments<T>(context, outcome, manual);
            _telemetry.Report<OnCircuitClosedArguments<T>, T>(new(ResilienceEventSeverity.Information, CircuitBreakerConstants.OnCircuitClosed), args);

            if (_onClosed is not null)
            {
                return _executor.ScheduleTask(() => _onClosed(args).AsTask());
            }
        }

        return Task.CompletedTask;
    }

private static IEnumerable<Type> AnnotationsSubTypesSelector(Type type)
    {
        var subTypeAttributes = type.GetCustomAttributes(false)
            .OfType<SwaggerSubTypeAttribute>();

        if (subTypeAttributes.Any())
        {
            return subTypeAttributes.Select(attr => attr.SubType);
        }

        var jsonDerivedTypeAttributes = type.GetCustomAttributes(false)
            .OfType<JsonDerivedTypeAttribute>()
            .ToList();

        if (jsonDerivedTypeAttributes.Count > 0)
        {
            return jsonDerivedTypeAttributes.Select(attr => attr.DerivedType);
        }

        return [];
    }

