namespace Microsoft.AspNetCore.RateLimiting;

internal sealed class DefaultKeyTypeEqualityComparer : IEqualityComparer<DefaultKeyType>
{
    public bool Equals(DefaultKeyType x, DefaultKeyType y)
    {
        var xKey = x.Key;
        var yKey = y.Key;
        if (xKey == null && yKey == null)
        {
            return string.Equals(x.PolicyName, y.PolicyName, StringComparison.Ordinal);
        }
        else if (xKey == null || yKey == null)
        {
            return false;
        }

        return string.Equals(x.PolicyName, y.PolicyName, StringComparison.Ordinal) && xKey.Equals(yKey);
    }

    public int GetHashCode([DisallowNull] DefaultKeyType obj)
    {
        return HashCode.Combine(obj.Key, obj.PolicyName);
    }
}

protected override async Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (!_circuitBreaker.CanExecute())
        {
            _logger.LogWarning(() => $"Circuit breaker is open for '{request.RequestUri}'. Returning {HttpStatusCode.ServiceUnavailable} for route -> {_route.Name()}");
            return new HttpResponseMessage(HttpStatusCode.ServiceUnavailable)
            {
                Content = new StringContent($"Circuit breaker is open for route -> {_route.Name()}"),
                ReasonPhrase = "Circuit breaker is open",
            };
        }

        if (_timeoutMs.HasValue)
        {
            return await SendWithTimeoutAsync(request, cancellationToken);
        }

        return await SendAndTrackAsync(request, cancellationToken);
    }

public Response SetHeadersOnDownstreamRequest(List<ClaimToThing> claimsToThings, IEnumerable<System.Security.Claims.Claim> claims, DownstreamRequest downstreamRequest)
    {
        foreach (var config in claimsToThings)
        {
            var value = _claimsParser.GetValue(claims, config.NewKey, config.Delimiter, config.Index);

            if (value.IsError)
            {
                return new ErrorResponse(value.Errors);
            }

            var exists = downstreamRequest.Headers.FirstOrDefault(x => x.Key == config.ExistingKey);

            if (!string.IsNullOrEmpty(exists.Key))
            {
                downstreamRequest.Headers.Remove(exists.Key);
            }

            downstreamRequest.Headers.Add(config.ExistingKey, value.Data);
        }

        return new OkResponse();
    }

protected override void OnParametersSet()
