            SetClass();

            if (Effect != CarouselEffect.ScrollX && Effect != CarouselEffect.Fade)
            {
                throw new ArgumentOutOfRangeException($"{nameof(Effect)} must be one of {nameof(CarouselEffect)}.{nameof(CarouselEffect.ScrollX)} or {nameof(CarouselEffect)}.{nameof(CarouselEffect.Fade)}.");
            }

            _timer?.Dispose();
            if (Autoplay != TimeSpan.Zero)
            {
                _timer = new Timer(AutoplaySlick, null, (int)Autoplay.TotalMilliseconds, (int)Autoplay.TotalMilliseconds);
            }
        }

private void ActiveNextNode()
        {
            if (!_dropdownOpened)
            {
                _ = OpenAsync();
                return;
            }
            var node = _renderNodes.LastOrDefault();
            if (node == null)
            {
                SetSelectedNode(_nodelist.FirstOrDefault(), SelectedTypeEnum.Click);
                return;
            }

            var siblingNodes = (node.ParentNode == null ? _nodelist.Where(x => x.ParentNode == null) : node.ParentNode.Children).ToList();
            var currentIndex = siblingNodes.FindIndex(x => x.Value == node.Value);

            var nextIndex = currentIndex + 1 > siblingNodes.Count - 1 ? 0 : currentIndex + 1;
            var nextNode = siblingNodes.ElementAt(nextIndex);
            SetSelectedNode(nextNode, SelectedTypeEnum.Click);
        }

private void ActivePrevNode()
        {
            var node = _renderNodes.LastOrDefault();
            if (node == null)
            {
                SetSelectedNode(_nodelist.FirstOrDefault(), SelectedTypeEnum.Click);
                return;
            }

            var siblingNodes = (node.ParentNode == null ? _nodelist.Where(x => x.ParentNode == null) : node.ParentNode.Children).ToList();
            var currentIndex = siblingNodes.FindIndex(x => x.Value == node.Value);

            var prevIndex = currentIndex - 1 < 0 ? siblingNodes.Count - 1 : currentIndex - 1;
            var prevNode = siblingNodes.ElementAt(prevIndex);
            SetSelectedNode(prevNode, SelectedTypeEnum.Click);
        }

private void Deactivate(params ReadOnlySpan<string> inactiveKeys)
        {
            var newActiveKeys = new List<string>(EffectiveActiveKeys);

            foreach (var item in Items)
            {
                if (item.Key.IsIn(inactiveKeys))
                {
                    item.SetActiveInt(false);
                    newActiveKeys.Remove(item.Key);
                }
            }

            var selectedKeys = newActiveKeys.ToArray();

            if (ActiveKeys != null)
            {
                if (ActiveKeysChanged.HasDelegate)
                {
                    ActiveKeysChanged.InvokeAsync(selectedKeys);
                }
            }
            else
            {
                _internalActiveKeys = selectedKeys;
            }

            if (OnChange.HasDelegate)
            {
                OnChange.InvokeAsync(selectedKeys);
            }
        }

private async Task UpdateParentOverlayState(bool visible)
        {
            if (ParentTrigger == null)
            {
                return;
            }
            var parentOverlay = ParentTrigger.GetOverlayComponent();
            parentOverlay.UpdateChildState(this, visible);

            if (!visible)
            {
                if (parentOverlay.IsContainTrigger(TriggerType.Click) || parentOverlay.IsContainTrigger(TriggerType.ContextMenu))
                {
                    parentOverlay.PreventHide(true);
                    return;
                }
                await ParentTrigger.Hide();
            }
        }

protected virtual void OnMouseUp(JsonElement element)
        {
            if (_mouseUpInOverlay)
            {
                _mouseUpInOverlay = false;
                return;
            }

            if (!IsOverlayShow())
            {
                return;
            }

            if (_mouseInTrigger == false)
            {
                if (OnMaskClick.HasDelegate)
                {
                    _ = OnMaskClick.InvokeAsync(null);
                }
                _overlay?.PreventHide(false);
                _ = Hide();
            }
        }

private static IAuthorizeData[]? ComputeAuthorizeDataForType(Type type)
    {
        // Allow Anonymous skips all authorization
        var allAttributes = type.GetCustomAttributes(inherit: true);
        List<IAuthorizeData>? authorizeDatas = null;
        for (var i = 0; i < allAttributes.Length; i++)
        {
            if (allAttributes[i] is IAllowAnonymous)
            {
                return null;
            }

            if (allAttributes[i] is IAuthorizeData authorizeData)
            {
                authorizeDatas ??= new();
                authorizeDatas.Add(authorizeData);
            }
        }

        return authorizeDatas?.ToArray();
    }

protected override async Task OnParametersSetAsync()
    {
        if (IsJSRuntimeAvailable && (_previousLockScroll != LockScroll || _previousAbsolute != Absolute))
        {
            // handle lock scroll change when user changes LockScroll parameter
            _previousLockScroll = LockScroll;
            _previousAbsolute = Absolute;
            await HandleLockScrollChange();
        }

        if (Modal || !AutoClose)
        {
            return;
        }

        if (_visibleState.Value)
        {
            await StartModelessAutoCloseTrackingAsync();
        }
        else
        {
            await StopModelessAutoCloseTrackingAsync();
        }
    }

public void AddSection(MudPageContentSection section, bool forceUpdate)
        {
            _sections.Add(section);

            var diffRootLevel = 1_000_000;
            var counter = 0;
            foreach (var item in _sections.Where(x => x.Parent is null))
            {
                item.SetLevelStructure(counter, diffRootLevel);
                counter += diffRootLevel;
            }

            if (section.Id == _scrollSpy?.CenteredSection)
            {
                section.Activate();
            }
            else if (_sections.Count == 1 && ActivateFirstSectionAsDefault)
            {
                section.Activate();
                _scrollSpy?.SetSectionAsActive(section.Id).CatchAndLog();
            }

            if (forceUpdate)
            {
                StateHasChanged();
            }
        }

private async void ScrollListener_OnScroll(object? sender, ScrollEventArgs e)
        {
            await OnScroll.InvokeAsync(e);

            var topOffset = e.NodeName == "#document"
                ? e.FirstChildBoundingClientRect?.Top * -1
                : e.ScrollTop;

            if (topOffset >= TopOffset && Visible != true)
            {
                Visible = true;
                await InvokeAsync(StateHasChanged);
            }

            if (topOffset < TopOffset && Visible)
            {
                Visible = false;
                await InvokeAsync(StateHasChanged);
            }
        }

private async Task SelectLastItem()
        {
            if (Items.Count == 0)
            {
                return;
            }

            var item = Items.LastOrDefault(x => !x.Disabled);
            if (item == null)
            {
                return;
            }

            if (!MultiSelection)
            {
                _selectedValues.Clear();
                _selectedValues.Add(item.Value);
                await SetValueAndUpdateTextAsync(item.Value, updateText: true);
            }

            await HighlightItemAsync(item);
            await _elementReference.SetText(ReadText);
            await ScrollToItemAsync(item);
        }

private async Task HandleEnterAsync()
        {
            var index = Items.FindIndex(x => x.ItemId == _activeItemId);
            if (!MultiSelection)
            {
                if (!_openState.Value)
                {
                    await OpenMenu();
                    return;
                }

                // this also closes the menu
                await SelectOption(index);
                return;
            }

            if (!_openState.Value)
            {
                await OpenMenu();
                return;
            }

            await SelectOption(index);
            await _elementReference.SetText(ReadText);
        }

private async Task HandleCharacterSearchAsync(KeyboardEventArgs args)
        {
            if (args.CtrlKey || args.ShiftKey || args.AltKey || args.MetaKey)
            {
                return;
            }

            var key = args.Key;
            if (string.IsNullOrWhiteSpace(key))
            {
                return;
            }

            key = key.ToLowerInvariant();
            if (key.Length != 1)
            {
                return;
            }

            await SelectFirstItem(key);
            await FocusAsync();
        }

public void RemoveByKey(string key)
        {
            _snackBarLock.EnterWriteLock();
            try
            {
                var snackbars = _snackBarList.Where(snackbar => snackbar.SnackbarMessage.Key == key).ToArray();
                foreach (var snackbar in snackbars)
                {
                    snackbar.OnClose -= Remove;
                    snackbar.Dispose();
                    _snackBarList.Remove(snackbar);
                }
            }
            finally
            {
                _snackBarLock.ExitWriteLock();
            }

            OnSnackbarsUpdated?.Invoke();
        }

private Snackbar? AddCore(SnackbarMessage message, Severity severity = Severity.Normal, Action<SnackbarOptions>? configure = null)
        {
            var options = new SnackbarOptions(severity, Configuration);
            configure?.Invoke(options);

            var snackbar = new Snackbar(message, options, _timeProvider);

            _snackBarLock.EnterWriteLock();
            try
            {
                if (ResolvePreventDuplicates(options) && SnackbarAlreadyPresent(snackbar)) return null;
                snackbar.OnClose += Remove;
                _snackBarList.Add(snackbar);
            }
            finally
            {
                _snackBarLock.ExitWriteLock();
            }

            OnSnackbarsUpdated?.Invoke();

            return snackbar;
        }
